class Solution:
    def findMinimumOperations(self, s1, s2, s3):
        minlen = min(len(s1), len(s2), len(s3))
        L = 0
        for i in range(minlen):
            if s1[i] == s2[i] == s3[i]:
                L += 1
            else:
                break
        if L == 0:
            return -1
        return (len(s1) - L) + (len(s2) - L) + (len(s3) - L)

