var findMinimumOperations = function(s1, s2, s3) {
    const minlen = Math.min(s1.length, s2.length, s3.length);
    let L = 0;
    for (let i = 0; i < minlen; i++) {
        if (s1[i] === s2[i] && s2[i] === s3[i]) {
            L += 1;
        } else {
            break;
        }
    }
    if (L === 0) return -1;
    return (s1.length - L) + (s2.length - L) + (s3.length - L);
};
